patterns.example_bad:
// Column-major traversal of row-major data
for (j = 0; j < width; j++)
  sum += A[tid + j * height]; // stride = height

patterns.example_good:
// Row-major traversal
for (j = 0; j < width; j++)
  sum += A[tid * width + j]; // stride = 1, coalesced

patterns.example_bad:
__global__ void kernel() {
  float a[64]; // 64 VGPRs just for this array
  // ... more register-heavy code
}

patterns.example_good:
__global__ void kernel() {
  __shared__ float a[64]; // offload to LDS
  // ... or reduce working set
}

patterns.example_bad:
for (int t = 0; t < tiles; t++) {
  load_tile(t);
  __syncthreads();  // wait
  compute(t);
  __syncthreads();
}

patterns.example_good:
load_tile(0);  // prefetch first tile
for (int t = 0; t < tiles; t++) {
  if (t + 1 < tiles) load_tile_async(t+1);  // prefetch next
  __syncthreads();
  compute(t);  // compute current while next is loading
  __syncthreads();
  swap_buffers();
}
